// Récupérer tous les éléments
const items = $input.all();

// Chercher le dossier 'template rapport' (insensible à la casse)
let templateFolderId = null;
let templateFolderName = null;

for (const item of items) {
  const data = item.json;
  if (data.mimeType === 'application/vnd.google-apps.folder') {
    const name = (data.name || '').toLowerCase().trim();
    if (name === 'template rapport' || name === 'template_rapport' || name === 'templaterapport') {
      templateFolderId = data.id;
      templateFolderName = data.name;
      break;
    }
  }
}

// Si dossier non trouvé
if (!templateFolderId) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: "Dossier 'template rapport' non trouvé",
      dossiersDisponibles: items
        .filter(i => i.json.mimeType === 'application/vnd.google-apps.folder')
        .map(i => i.json.name)
        .slice(0, 20),
      contenu: { sousDossiers: [], fichiers: [] }
    }
  }];
}

// Filtrer le contenu du dossier (éléments dont le parent est templateFolderId)
// Note: Sans le champ 'parents', on ne peut pas faire ce filtrage
// On retourne donc juste l'info du dossier trouvé

return [{
  json: {
    success: true,
    found: true,
    folderId: templateFolderId,
    folderName: templateFolderName,
    message: "Dossier trouvé - utilisez l'ID pour lister son contenu"
  }
}];

// Construire la réponse avec le contenu du dossier
const items = $input.all();

const sousDossiers = [];
const fichiers = [];

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    sousDossiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'dossier'
    });
  } else {
    fichiers.push({
      id: data.id,
      nom: data.name || 'Sans nom',
      type: 'fichier',
      mimeType: data.mimeType || 'unknown'
    });
  }
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossier: 'template rapport',
    statistiques: {
      totalSousDossiers: sousDossiers.length,
      totalFichiers: fichiers.length
    },
    contenu: {
      sousDossiers: sousDossiers,
      fichiers: fichiers
    }
  }
}];
